import json
import re
import logging
import os
import boto3
from botocore.exceptions import ClientError

# Configure logging - ensure no sensitive data is logged
logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Allowlisted origins - NEVER use wildcard "*" in production
ALLOWED_ORIGINS = os.environ.get("ALLOWED_ORIGINS", "").split(",")
# Example: "http://localhost:3000,https://staging.example.com,https://app.example.com"

ALLOWED_METHODS = "GET,OPTIONS"
ALLOWED_HEADERS = "Content-Type,Authorization,X-Requested-With"
MAX_AGE = "3600"

# Input validation constants
MAX_USER_ID_LENGTH = 64
USER_ID_PATTERN = re.compile(r"^[a-zA-Z0-9\-_]+$")


def get_cors_headers(event):
    """
    Return CORS headers with explicit origin allowlist validation.
    NEVER use Access-Control-Allow-Origin: * with credentials or sensitive data.
    """
    headers = {
        "Content-Type": "application/json",
        "X-Content-Type-Options": "nosniff",
        "X-Frame-Options": "DENY",
        "Cache-Control": "no-store",
        "Strict-Transport-Security": "max-age=31536000; includeSubDomains",
    }

    request_origin = ""
    if event and event.get("headers"):
        # Headers may be case-insensitive depending on API Gateway config
        raw_headers = event.get("headers", {})
        for key, value in raw_headers.items():
            if key.lower() == "origin":
                request_origin = value
                break

    # Validate origin against explicit allowlist
    if request_origin in ALLOWED_ORIGINS:
        headers["Access-Control-Allow-Origin"] = request_origin
        headers["Access-Control-Allow-Methods"] = ALLOWED_METHODS
        headers["Access-Control-Allow-Headers"] = ALLOWED_HEADERS
        headers["Access-Control-Max-Age"] = MAX_AGE
        headers["Vary"] = "Origin"
    else:
        # Do not set any CORS headers for disallowed origins
        logger.warning("Rejected CORS request from origin: %s", request_origin[:200])

    return headers


def validate_user_id(user_id):
    """Validate user ID input to prevent injection attacks."""
    if not user_id:
        return False, "User ID is required"
    if not isinstance(user_id, str):
        return False, "User ID must be a string"
    if len(user_id) > MAX_USER_ID_LENGTH:
        return False, "User ID exceeds maximum length"
    if not USER_ID_PATTERN.match(user_id):
        return False, "User ID contains invalid characters"
    return True, None


def validate_authorization(event):
    """
    Validate the authorization token from the request.
    In production, use API Gateway authorizers (Lambda or Cognito) for this.
    This is a defense-in-depth check.
    """
    headers = event.get("headers", {})
    auth_header = None
    for key, value in headers.items():
        if key.lower() == "authorization":
            auth_header = value
            break

    if not auth_header:
        return False, "Missing authorization header"

    if not auth_header.startswith("Bearer "):
        return False, "Invalid authorization scheme"

    token = auth_header[7:]
    if not token or len(token) > 2048:
        return False, "Invalid token"

    # In production: validate JWT signature, expiration, audience, issuer
    # Use AWS Cognito, API Gateway Lambda Authorizer, or similar
    # NEVER log the actual token
    logger.info("Authorization token present (not logged for security)")

    return True, None


def get_user_from_dynamodb(user_id):
    """
    Fetch user data from DynamoDB using parameterized queries (safe from injection).
    DynamoDB SDK handles input safely, but we still validate input beforehand.
    """
    table_name = os.environ.get("USERS_TABLE_NAME")
    if not table_name:
        logger.error("USERS_TABLE_NAME environment variable not set")
        return None

    try:
        dynamodb = boto3.resource("dynamodb")
        table = dynamodb.Table(table_name)

        response = table.get_item(
            Key={"userId": user_id},
            # Only return specific attributes - least privilege data access
            ProjectionExpression="userId, displayName, email, #r, createdAt",
            ExpressionAttributeNames={"#r": "role"},
        )

        item = response.get("Item")
        if not item:
            return None

        # Sanitize output - never return internal fields, secrets, or hashed passwords
        safe_user_data = {
            "userId": item.get("userId", ""),
            "displayName": item.get("displayName", ""),
            "email": item.get("email", ""),
            "role": item.get("role", ""),
            "createdAt": item.get("createdAt", ""),
        }

        return safe_user_data

    except ClientError as e:
        # Log error code but not full exception which may contain sensitive data
        logger.error("DynamoDB error code: %s", e.response["Error"]["Code"])
        return None


def build_response(status_code, body, event):
    """Build a standardized API response with security headers."""
    cors_headers = get_cors_headers(event)
    return {
        "statusCode": status_code,
        "headers": cors_headers,
        "body": json.dumps(body, default=str),
    }


def lambda_handler(event, context):
    """
    Main Lambda handler for user data API.
    Secured with input validation, authorization, CORS allowlisting, and least privilege.
    """
    try:
        http_method = event.get("httpMethod", event.get("requestContext", {}).get("http", {}).get("method", ""))

        # Handle CORS preflight
        if http_method == "OPTIONS":
            return build_response(204, "", event)

        # Only allow GET method
        if http_method != "GET":
            return build_response(405, {"error": "Method not allowed"}, event)

        # Validate authorization (defense in depth - primary auth should be at API Gateway level)
        auth_valid, auth_error = validate_authorization(event)
        if not auth_valid:
            logger.warning("Authorization failed: %s", auth_error)
            # Generic error message - don't leak auth failure details
            return build_response(401, {"error": "Unauthorized"}, event)

        # Extract and validate user ID from path parameters
        path_params = event.get("pathParameters") or {}
        user_id = path_params.get("userId", "")

        is_valid, validation_error = validate_user_id(user_id)
        if not is_valid:
            logger.warning("Invalid user ID input rejected")
            return build_response(400, {"error": "Invalid request parameters"}, event)

        # Fetch user data
        user_data = get_user_from_dynamodb(user_id)

        if user_data is None:
            return build_response(404, {"error": "User not found"}, event)

        return build_response(200, {"data": user_data}, event)

    except Exception:
        # Log for debugging but return generic error to client
        logger.exception("Unhandled exception in lambda_handler")
        return build_response(500, {"error": "Internal server error"}, event)


